'use strict';

class FlightPool {
  constructor(loader) {
    this.loader = loader;
    this.inflight = new Map();
  }

  load(key, signal) {
    let flight = this.inflight.get(key);
    if (!flight) {
      const controller = new AbortController();
      const promise = Promise.resolve().then(() => this.loader(key, controller.signal));
      flight = { controller, promise };
      this.inflight.set(key, flight);
      promise.finally(() => {
        if (this.inflight.get(key) === flight) this.inflight.delete(key);
      }).catch(() => {});
    }

    if (signal) {
      if (signal.aborted) {
        flight.controller.abort(signal.reason);
      } else {
        signal.addEventListener('abort', () => flight.controller.abort(signal.reason), { once: true });
      }
    }
    return flight.promise;
  }
}

module.exports = { FlightPool };

