'use strict';

const { FlightPool } = require('./flightPool');

class ResourceClient {
  constructor(loader, pool = null) {
    this.pool = pool || new FlightPool(loader);
    this.cache = new Map();
  }

  get(key, signal) {
    if (!this.cache.has(key)) {
      this.cache.set(key, this.pool.load(key, signal));
    }
    return this.cache.get(key);
  }
}

module.exports = { ResourceClient };

