'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { ResourceClient } = require('../src/resourceClient');
const { loadNormalized } = require('../src/keyPolicy');

test('concurrent readers share one successful load', async () => {
  let calls = 0;
  let release;
  const client = new ResourceClient(async (key) => {
    calls += 1;
    return new Promise((resolve) => { release = () => resolve({ key, revision: 4 }); });
  });
  const first = client.get('alpha');
  const second = client.get('alpha');
  await Promise.resolve();
  release();
  assert.deepEqual(await first, { key: 'alpha', revision: 4 });
  assert.deepEqual(await second, { key: 'alpha', revision: 4 });
  assert.equal(calls, 1);
});

test('a normalized successful value remains cached', async () => {
  let calls = 0;
  const client = new ResourceClient(async (key) => ({ key, revision: ++calls }));
  assert.deepEqual(await loadNormalized(client, ' Stable '), { key: 'stable', revision: 1 });
  assert.deepEqual(await loadNormalized(client, 'STABLE'), { key: 'stable', revision: 1 });
  assert.equal(calls, 1);
});
